where pe.leave_flag = 1
  and pe.enabled_flag = 1
  and pe.id_number = #{idNumber,jdbcType=VARCHAR}
  and pe.id != #{employeeId,jdbcType=BIGINT}

select pe.id,pe.name, pe.work_card, pe.email_inside, fdev.ext_dept_name AS dept_name, fdev.ext_department_name AS department, fdev.ext_team_name AS team, pej.job_name as pej_fj_job_name, 0 as need_check,petto.tele as teleoffice,pettf.tele as telefamily
, ISNULL(pett.id, -1) pett_id,
, ISNULL(peee.id, -1) peee_id,
from pm_employee pe left outer join pm_employee_job pej on pe.id = pej.employee_id and pej.job_main_flag = 1 and pej.enabled_flag = 1 left outer join fnd_dept_ext_v fdev on pej.dept_id = fdev.id and fdev.enabled_flag = 1 and fdev.deleted_flag = 0 outer apply (SELECT TOP(1) pett_ap.* FROM V_pm_tele_sumList pett_ap WHERE pett_ap.employee_id = pe.id AND pett_ap.enabled_flag = 1 AND pett_ap.tele_type = 2 ) pett outer apply (SELECT TOP(1) peee_ap.* FROM pm_employee_emergency peee_ap WHERE peee_ap.employee_id = pe.id AND peee_ap.enabled_flag = 1 ) peee outer apply (SELECT TOP(1) petto_ap.* FROM V_pm_tele_sumList petto_ap WHERE petto_ap.employee_id = pe.id AND petto_ap.enabled_flag = 1 AND petto_ap.tele_type = 1 ) petto outer apply (SELECT TOP(1) petto_ap.* FROM V_pm_tele_sumList petto_ap WHERE petto_ap.employee_id = pe.id AND petto_ap.enabled_flag = 1 AND petto_ap.tele_type = 3 ) pettf where 1 = 1
and pe.leave_flag = #{criteria.leaveFlag,jdbcType=BIT}
and pe.enabled_flag = #{criteria.enabledFlag,jdbcType=BIT}

select pej.employee_id, isnull(pe.email_inside, fu.email) as email
from
fnd_dept fd left join pm_employee_job pej on pej.dept_id = fd.id and fd.admin_job_id = pej.job_id and pej.enabled_flag = 1 and fd.enabled_flag = 1 and pej.job_main_flag = 1 left join fnd_user fu on fu.employee_id = pej.employee_id left join fnd_dept fdt on fd.id = fdt.parent_id and fdt.enabled_flag = 1 left join pm_employee pe on fu.employee_id = pe.id and pe.enabled_flag =1 where fdt.id = #{deptId, jdbcType=BIGINT}




AND (pej.job_name LIKE '%班长' or pej.job_name LIKE '%组长' or pej.job_name LIKE '%站长')



and fdev.ext_dept_name = #{map.deptName, jdbcType=VARCHAR}




and   fdev.ext_department_name = #{map.departmentName, jdbcType=VARCHAR}




and fdev.ext_team_name = #{map.teamName, jdbcType=VARCHAR}




and  pe.work_card = #{map.workCard,jdbcType=VARCHAR}



 order by   fdev.ext_dept_name , pej.job_name desc




