ER})) * 5)) + 1, 1 ) >= 5 then convert(int, (convert(decimal(10,3), ((case when year(dateadd(yyyy, 1, peen.entry_time)) < year(getdate()) then #{dayNum, jdbcType = INTEGER} else dbo.get_remaining_day(peen.entry_time, 1, #{dayNum, jdbcType = INTEGER}) end) / convert(decimal(10,3),#{dayNum, jdbcType = INTEGER}) * 5)))) + convert(float, 0.5) else convert(int, (convert(decimal(10,3), ((case when year(dateadd(yyyy, 1, peen.entry_time)) < year(getdate()) then #{dayNum, jdbcType = INTEGER} else dbo.get_remaining_day(peen.entry_time, 1, #{dayNum, jdbcType = INTEGER}) end) / convert(decimal(10,3),#{dayNum, jdbcType = INTEGER}) * 5)))) end -- 入司满1年，工龄未满10年结束 else -- 其它赋0 0 end end end end end end end from pm_employee pe outer apply ( select top(1) peen_ap.* from pm_employee_entry peen_ap where peen_ap.employee_id = pe.id AND peen_ap.enabled_flag = 1 ) peen where pe.enabled_flag = 1 and pe.leave_flag = 0 and pe.employee_type <> '临时员工'
